class Solution(object):
    def minOperations(self, k):
        if k == 1:
            return 0
        best = k - 1
        for a in range(k):
            v = 1 + a
            b = (k + v - 1) // v - 1
            if b < 0:
                b = 0
            best = min(best, a + b)
        return best
